import { Link } from "react-router-dom";

export const Navbar = () => {
    return(
        <div className="navbar">
            <Link to="/" >Home</Link>
            <Link to="/songs" >Songs</Link>
            <Link to="/search" >Search</Link>
        </div>
    );
}
